<template>
  <div class="cus-details">
    <template v-if="isEdit == false">
      <el-card>
        <el-row>
          <el-col :span="3">
            <img class="cus-details-img" src="@/assets/img/adapay/store.png" alt="">
          </el-col>
          <el-col :span="20">
            <div class="cus-details-flex">
              <p class="cus-details-row">{{ infoList.name }}</p>
              <div class="cus-details-pfonts cus-margin-40">
                <i class="el-icon-location-outline cus-icon" />
                <span>{{ infoList.province + infoList.city || '-' }}</span>
              </div>
            </div>
            <p class="cus-details-pfonts">
              <i class="el-icon-s-custom cus-icon" />
              <span>{{ infoList.contact || '-' }}</span>
            </p>
            <p class="cus-details-pfonts">
              <i class="el-icon-time cus-icon" />
              <span>{{ infoList.hour || '-' }}</span>
            </p>
            <div class="cus-details-flex">
              <div class="cus-details-pfonts">
                <i class="el-icon-phone cus-icon" />
                <span>{{ infoList.mobile || '-' }}</span>
                （企業電話）
              </div>
              <div class="cus-details-pfonts cus-margin-50">
                <i class="el-icon-message cus-icon" />
                <span>{{ infoList.email }}</span>
                （企業郵箱）
              </div>
            </div>
          </el-col>
        </el-row>
        <el-row style="margin-top: 10px">
          <el-tag
            v-for="item in tagsList"
            :key="item.name"
            :type="item.type"
            size="small"
            class="cus-details-tags"
          >
            {{ item.name }}
          </el-tag>
        </el-row>
      </el-card>
      <el-card>
        <el-tabs v-model="activeName" class="cus-details-tabs" @tab-click="tabChange">
          <el-tab-pane v-if="loginType === 'admin'" label="基本訊息" name="first">
            <BaseModal :span="20" :label-list="baseInfo" :info="infoList" title="地理位置" />
            <BaseModal
              v-if="is_rel_dealer"
              :span="20"
              :label-list="otherInfo"
              :info="dealerList"
              title="其他訊息"
            />
          </el-tab-pane>
          <el-tab-pane v-if="is_openAccount" label="開戶訊息" name="second">
            <BaseModal
              :span="7"
              :label-list="member_type === 'corp' ? enterPriseList : personInfo"
              :info="accountInfo"
              :title="
                member_type === 'corp'
                  ? `企業訊息 ${accountInfo.audit_desc_1 || ''}`
                  : '個人訊息 ' + `${accountInfo.audit_desc_1 || ''}`
              "
            />
            <BaseModal
              :span="7"
              :label-list="member_type === 'corp' ? enterAccountInfo : accountList"
              :info="accountInfo"
              :title="'結算帳戶訊息' + `${accountInfo.audit_desc_2 || ''}`"
            />
            <BaseModal
              v-if="loginType === 'admin'"
              :span="7"
              :label-list="
                is_rel_dealer && is_openAccount && member_type === 'corp'
                  ? enterSplitAccountList
                  : splitAccountList
              "
              :info="split_ledger_info"
              title="分帳訊息"
            />
            <el-card v-if="member_type === 'corp'">
              <div slot="header">其他訊息</div>
              <div class="body">
                <el-row class="load-btn">
                  <el-col :span="4" style="text-align: right; padding-right: 10px"
                    >
附件訊息：
</el-col
                  >
                  <el-col v-if="member_type === 'corp'" :span="20" class="cus-btn">
                    <el-button type="text" @click="dowloadFile(infoList.attach_file)"
                      >
附件
</el-button
                    >
                  </el-col>
                  <span v-else>-</span>
                </el-row>
              </div>
            </el-card>
            <div v-if="datapass_block != 1 && loginType != 'admin'" class="btn">
              <el-button v-if="accountInfo.audit_state != 'A'" type="primary" @click="editHandle"
                >
編輯
</el-button
              >
              <el-button v-if="accountInfo.audit_state == 'A'">審核中</el-button>
            </div>
          </el-tab-pane>
          <el-tab-pane
            v-if="!is_openAccount && loginType === 'distributor'"
            label="開戶訊息"
            name="second"
          >
            <el-row style="height: 350px" type="flex" justify="center" align="middle">
              <span style="color: #ccc">--暫無開戶訊息--</span>
            </el-row>
          </el-tab-pane>
          <el-tab-pane v-if="loginType === 'admin'" label="操作記錄" name="third">
            <el-timeline :reverse="false" class="cus-timeline">
              <el-timeline-item
                v-for="(item, index) in logList"
                :key="index"
                :timestamp="item.create_date"
              >
                {{ item.content }}
              </el-timeline-item>
            </el-timeline>
            <el-pagination
              layout="total, sizes, prev, pager, next"
              :current-page.sync="params.page"
              :page-sizes="[10, 20, 50]"
              :page-size="params.page_size"
              :total="total_count"
              @current-change="handleCurrentChange"
              @size-change="handleSizeChange"
            />
          </el-tab-pane>
        </el-tabs>
      </el-card>
      <el-row v-if="is_rel_dealer && loginType === 'admin'" class="cus-details-bot">
        <el-button type="primary" size="small" plain @click="handleModalClick(true, is_openAccount)"
          >
解除關聯
</el-button
        >
      </el-row>
      <RemoveShipModal
        :visible="visible"
        :info="infoList"
        :content="modalContent"
        @handleClick="handleModalClick"
      />
    </template>
    <template v-else>
      <editAccount
        :active-name="accountInfo.member_type"
        :info="accountInfo"
        @back="back"
      />
    </template>
  </div>
</template>
<script>
import { getDistributorInfo } from '@/api/marketing'
import { getAdapayLogList } from '@/api/adapay/dealer'
import BaseModal from '@/view/mall/marketing/component/BaseModal'
import RemoveShipModal from '@/view/mall/marketing/component/RemoveShipModal'
import editAccount from './component/editAccount.vue'

export default {
  components: { BaseModal, RemoveShipModal, editAccount },
  data() {
    return {
      datapass_block: null, //數據是否脫敏
      isEdit: false,
      activeName: 'first',
      distributor_id: 0,
      infoList: {},
      loginType: '',
      accountInfo: {}, // 結算帳戶訊息
      split_ledger_info: {}, // 分帳訊息
      dealerList: {}, // 經銷商訊息
      member_type: 'corp',
      is_openAccount: true,
      is_rel_dealer: true,
      visible: false,
      modalContent: '',
      tagsList: [],
      logList: [],
      total_count: 0,
      params: {
        page: 1,
        page_size: 10
      },
      baseInfo: [
        // 地理位置
        { name: '地理位置', field: 'store_address' },
        { name: '地圖定位', field: 'qqmapimg', type: 'pic' },
        { name: '店鋪經緯度', field: '', filter: this.addressFilter }
      ],
      otherInfo: [
        // 其他
        { name: '關聯經銷商', field: 'username' }
      ],
      enterPriseList: [
        // 企業訊息
        { name: '法人姓名', field: 'legal_person' },
        { name: '法人身份證號碼', field: 'legal_cert_id' },
        { name: '法人證件有效期', field: 'legal_cert_id_expires' },
        { name: '營業執照號', field: 'social_credit_code' },
        { name: '商戶有效日期', field: 'social_credit_code_expires' },
        { name: '經營範圍', field: 'business_scope' },
        { name: '法人電話號碼', field: 'tel_no' },
        { name: '企業地址', field: 'address' },
        { name: '郵編', field: 'zip_code' }
      ],
      enterAccountInfo: [
        // 結算帳戶訊息
        { name: '結算銀行卡號', field: 'card_no' },
        { name: '結算銀行卡開戶姓名', field: 'card_name' },
        { name: '結算銀行卡所屬銀行', field: 'bank_name' },
        { name: '結算銀行帳戶類型', field: 'bank_acct_type', filter: this.bankFilter }
      ],
      enterSplitAccountList: [
        // 企業分帳
        { name: '手續費扣費方式', field: 'adapay_fee_mode', filter: this.adapayFilter },
        { name: '總部分帳占比', field: 'headquarters_proportion', filter: this.headquartersFilter },
        { name: '經銷商分帳占比', field: 'dealer_proportion', filter: this.dealerFilter }
      ],
      personInfo: [
        // 個人訊息
        { name: '用戶姓名', field: 'user_name' },
        { name: '用戶手機號碼', field: 'tel_no' },
        { name: '法人身份證號碼', field: 'cert_id' }
      ],
      accountList: [
        // 個人結算訊息
        { name: '開戶人姓名', field: 'bank_card_name' },
        { name: '銀行預留手機號碼', field: 'bank_tel_no' },
        { name: '銀行帳號', field: 'bank_card_id' },
        { name: '開戶人證件號碼', field: 'bank_cert_id' }
      ],
      splitAccountList: [
        // 個人分帳
        { name: '手續費扣費方式', field: 'adapay_fee_mode', filter: this.adapayFilter },
        { name: '總部分帳占比', field: 'headquarters_proportion', filter: this.headquartersFilter }
      ]
    }
  },
  mounted() {
    if (this.$route.query.distributor_id || this.$store.getters.login_type === 'distributor') {
      this.distributor_id = this.$route.query.distributor_id ? this.$route.query.distributor_id : 0
      this.loginType = this.$store.getters.login_type
      if (this.$store.getters.login_type === 'distributor' || this.is_openAccount) {
        this.activeName = 'second'
      }
      this.getTabDetail()
    }
  },
  methods: {
    handleCurrentChange(page_num) {
      this.params.page = page_num
      this.getLogList()
    },
    handleSizeChange(pageSize) {
      this.params.page = 1
      this.params.page_size = pageSize
      this.getLogList()
    },
    tabChange(e) {
      this.activeName = e.name
      if (e.name == 'third') {
        this.params.page = 1
        this.getLogList()
      }
    },

    editHandle() {
      this.isEdit = true
    },
    addressFilter() {
      const { lat, lng } = this.infoList
      if (lat && lng) {
        return lng + ' - ' + lat
      } else {
        return '-'
      }
    },
    getTabDetail() {
      getDistributorInfo({ distributor_id: this.distributor_id })
        .then((response) => {
          console.log(response)
          const { is_openAccount, is_rel_dealer, adapayMemberInfo, dealer, datapass_block } =
            response.data.data || {}
          const {
            basicInfo: { auto_sync_goods, is_ziti, is_delivery, company_dada_open }
          } = adapayMemberInfo || {}
          this.infoList = response.data.data
          this.datapass_block = datapass_block
          this.split_ledger_info = adapayMemberInfo.split_ledger_info || {}
          this.is_openAccount = is_openAccount
          this.is_rel_dealer = is_rel_dealer
          this.dealerList = dealer || {}
          this.accountInfo = adapayMemberInfo || {}
          this.member_type = adapayMemberInfo.member_type
          if (auto_sync_goods) {
            this.tagsList.push({ name: '自動上架商品', type: 'danger' })
          }
          if (is_ziti) {
            this.tagsList.push({ name: '支持自取', type: '' })
          }
          if (is_delivery) {
            this.tagsList.push({ name: '支持快遞', type: 'success' })
          }
          if (company_dada_open) {
            this.tagsList.push({ name: '同城配', type: 'warning' })
          }
        })
        .catch((error) => {
          this.loading = false
          this.$message({
            type: 'error',
            message: '獲取詳情出錯'
          })
        })
    },
    getLogList() {
      getAdapayLogList({
        log_type: 'distributor',
        ...this.params,
        distributor_id: this.distributor_id
      })
        .then((response) => {
          this.logList = response.data.data.list || {}
          this.total_count = response.data.data.total_count || 0
        })
        .catch((error) => {
          this.loading = false
          this.$message({
            type: 'error',
            message: '獲取日誌出錯'
          })
        })
    },
    handleModalClick(visible, is_openAccount) {
      const { username } = this.dealerList
      this.visible = visible
      if (visible && !is_openAccount) {
        this.modalContent = `請確認是否解除該店鋪與【${username}】的關聯`
      } else if (visible && is_openAccount) {
        this.infoList = { ...this.infoList, audit_state: '3' }
        this.modalContent = '如解除關聯，需重新設置總部分帳占比。'
      }
    },
    bankFilter() {
      let { bank_acct_type } = this.infoList
      let returnValue = ''
      switch (bank_acct_type) {
        case '1':
          returnValue = '對公'
          break
        case '2':
          returnValue = '對公'
          break
      }
      return returnValue
    },
    adapayFilter() {
      let { adapay_fee_mode } = this.split_ledger_info
      let returnValue = ''
      switch (adapay_fee_mode) {
        case 'I':
          returnValue = '內扣'
          break
        case 'O':
          returnValue = '外扣'
          break
      }
      return returnValue
    },
    headquartersFilter() {
      // 總部分帳占比過濾
      let { headquarters_proportion } = this.split_ledger_info
      let value = this.split_ledger_info.headquarters_proportion
      return value ? value + '%' : '-'
    },
    dealerFilter() {
      // 經銷商分帳占比過濾
      let { dealer_proportion } = this.split_ledger_info
      let value = this.split_ledger_info.dealer_proportion
      return value ? value + '%' : '-'
    },
    dowloadFile(url) {
      let link = document.createElement('a')
      link.style.display = 'none'
      link.href = url
      document.body.appendChild(link)
      link.click()
      this.$message({
        type: 'success',
        message: '下載成功'
      })
    },
    back() {
      this.isEdit = false
    }
  }
}
</script>
